class Solution {
public:
    int findUnsortedSubarray(vector<int>& nums) {
        vector<int> sorted_nums = nums;
        sort(sorted_nums.begin(), sorted_nums.end());
        int start = nums.size(), end = 0;
        for (int i = 0; i < nums.size(); i++) {
            if (nums[i] != sorted_nums[i]) {
                start = min(start, i);
                end = max(end, i);
            }
        }
        if (end - start >= 0) {
            return end - start + 1;
        }
        return 0;
    }
};
```
